package com.kalyani.car_rental_backend.notification.controller;import com.kalyani.car_rental_backend.exception.ResourceNotFoundException;import com.kalyani.car_rental_backend.notification.entity.Notification;import com.kalyani.car_rental_backend.notification.repository.NotificationRepository;import com.kalyani.car_rental_backend.response.ApiResponse;import org.springframework.http.ResponseEntity;import org.springframework.security.core.Authentication;import org.springframework.web.bind.annotation.*;import java.util.*;
@RestController @RequestMapping("/notifications") public class NotificationController{private final NotificationRepository repo;public NotificationController(NotificationRepository r){repo=r;}@GetMapping public ResponseEntity<ApiResponse<List<Map<String,Object>>>> list(Authentication a){return ResponseEntity.ok(ApiResponse.success(repo.findByUserEmailIgnoreCaseOrderByCreatedAtDesc(a.getName()).stream().map(this::out).toList(),"Notifications loaded"));}@GetMapping("/unread-count")public ResponseEntity<ApiResponse<Long>> count(Authentication a){return ResponseEntity.ok(ApiResponse.success(repo.countByUserEmailIgnoreCaseAndReadFlagFalse(a.getName()),"Unread count loaded"));}@PatchMapping("/{id}/read")public ResponseEntity<ApiResponse<Map<String,Object>>> read(@PathVariable Long id,Authentication a){var n=owned(id,a.getName());n.setReadFlag(true);return ResponseEntity.ok(ApiResponse.success(out(repo.save(n)),"Notification marked as read"));}@PatchMapping("/read-all")public ResponseEntity<ApiResponse<Void>> all(Authentication a){repo.findByUserEmailIgnoreCaseOrderByCreatedAtDesc(a.getName()).forEach(n->{n.setReadFlag(true);repo.save(n);});return ResponseEntity.ok(ApiResponse.success(null,"All notifications marked as read"));}private Notification owned(Long id,String e){var n=repo.findById(id).orElseThrow(()->new ResourceNotFoundException("Notification not found"));if(!n.getUser().getEmail().equalsIgnoreCase(e))throw new IllegalArgumentException("You cannot access this notification");return n;}private Map<String,Object> out(Notification n){Map<String,Object>m=new LinkedHashMap<>();m.put("id",n.getId());m.put("title",n.getTitle());m.put("message",n.getMessage());m.put("type",n.getType());m.put("read",n.isReadFlag());m.put("createdAt",n.getCreatedAt());return m;}}
